      "depends_on": [1]
    },
    {
      "step": 3,
      "title": "ADB（5555）三阶段权限验证：connect → shell → id",
      "objective": "确认 ADB 服务在无认证前提下是否提供 root shell 访问能力",
      "success_criteria": "成功执行 adb connect 127.0.0.1:5555 && adb -s 127.0.0.1:5555 shell 'id' 并返回 uid=0(gid=0)",
      "depends_on": [1]
    },
    {
      "step": 4,
      "title": "基于 HTTP Diag 接口的轻量级命令注入/路径遍历验证",
      "objective": "对已发现的可交互端点（如 /api/v1/exec?cmd=）尝试基础注入（id、whoami、ls /proc/self）并捕获回显",
      "success_criteria": "至少 1 次请求返回与系统命令执行一致的结构化输出（如 JSON 中含 'stdout' 字段含 uid=0 或进程列表）",
      "depends_on": [1]
    },
    {
      "step": 5,
      "title": "RTSP 日志泄露内容解析与敏感字段提取",
      "objective": "对 RTSP 响应体进行正则匹配，提取路径、版本号、错误堆栈、硬编码密钥等高危信息",
      "success_criteria": "从响应 body 中成功提取 ≥3 行含敏感语义的文本（如 '/etc/passwd'、'v2.4.1'、'DEBUG: key=abc123'）",
      "depends_on": [2]
    }
  ],
  "guardrails": [
    "避免重复调用同一工具（如连续两次未修改参数的 curl 请求）",
    "避免错误扩散（任一步骤失败时，不自动触发下游依赖步骤，除非显式标记为 soft_dependency）",
    "连续失败时切换策略或终止（若 step 1 和 step 3 均失败，则终止流程并标记为 'requires_manual_recon'）"
  ]
}

